+// Returns true if (n, m) is the (XorVMask, MaskAll) part of an "andNot"
+// pattern: n is XorVMask, m is all-ones, and n is used only by an AndVMask.
+// That gives (AndVMask vm1 (XorVMask vm2 (MaskAll m1))). Cloning m allows
+// the matcher to share the MaskAll and match the andNot rule.
+// Limitation: the "andNot" rule still cannot be matched if "m" has other
+// uses outside this pattern.
+static bool is_vector_mask_bitwise_andnot_pattern(Node* n, Node* m) {
+  if (n == nullptr || m == nullptr) {
+    return false;
+  }
+
+  if (n->Opcode() == Op_XorVMask &&
+      VectorNode::is_all_ones_vector(m)) {
+    // Check whether n is only used by an AndVMask node.
+    if (n->outcnt() == 1) {
+      Node* u = n->unique_out();
+      if (u->Opcode() == Op_AndVMask) {
+        return true;
+      }
+    }
+  }
+  return false;
+}
